import { useEffect, useState } from "react";
import {
  approveUser,
  disApproveUser,
  GetAllProfiles,
  getFromBucket,
} from "../service/Profile.service";

export function useGetAllProfiles() {
  // In future you can edit here for creating pagination and update
  const [users, setUsers] = useState([]);
  const [trigger, settrigger] = useState(false);
  const [showModal, setShowModal] = useState(null);

  async function handleApproval(approved, id) {
    try {
      if (approved) {
        await disApproveUser(id);
      } else {
        await approveUser(id);
      }
    } catch (error) {
    } finally {
      settrigger(!trigger);
    }
  }

  useEffect(() => {
    async function list() {
      const user = await GetAllProfiles();
      const userData = await Promise.all(user.data.listProfiles.items.map(async(obj)=>{
        if(obj.id_card){

          obj.id_card = await getFromBucket(obj.id_card);
        } 
        return obj
      }))
      setUsers(userData);
    }
    list();
  }, [trigger]);

  return { handleApproval, users, showModal, setShowModal };
}
