import React from "react";
import { CircleX } from "lucide-react";

const Modal = ({ isVisible, imageUrl, onClose }) => {
  if (!isVisible) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center z-50 bg-black bg-opacity-50 backdrop-blur-sm transition-opacity duration-300">
      <div className="relative h-auto bg-white p-6 rounded-2xl shadow-2xl max-w-3xl w-full overflow-hidden transform transition-transform scale-100 hover:scale-105">
        <button
          className="absolute top-3 right-2 text-gray-600 hover:text-red-600 transition"
          onClick={onClose}
        >
          <CircleX size={24} />
        </button>
        <img
          src={imageUrl}
          alt="ID Card"
          className="max-w-full  rounded-lg shadow-md"
        />
      </div>
    </div>
  );
};

export default Modal;